const cleanArg = (v) => { const t = String(v == null ? '' : v).trim(); return /^\{[a-zA-Z0-9_]+\}$/.test(t) ? '' : t; };
const norm = (s) => (s || '').replace(/\u00a0/g, ' ').replace(/\s+/g, ' ').trim();
const origin = location.origin;
const cards = Array.from(document.querySelectorAll('[data-component-type="s-search-result"]'));
const out = [];
for (const card of cards) {
  const asin = (card.getAttribute('data-asin') || '').trim();
  const h2 = card.querySelector('h2');
  if (!h2) continue;
  const titleSpan = h2.querySelector('span');
  const title = norm(titleSpan ? titleSpan.innerText : h2.innerText);
  if (!title) continue;
  if (card.classList.contains('s-widget-spacing-small') && !asin) continue;
  let anchor = h2.closest('a[href]');
  if (!anchor) anchor = card.querySelector('a.a-link-normal[href*="/dp/"], a.a-link-normal[href*="/gp/"]');
  let rawUrl = anchor ? (anchor.getAttribute('href') || '') : '';
  let url = '';
  if (asin) {
    url = origin + '/dp/' + asin;
  } else if (rawUrl) {
    url = rawUrl.startsWith('/') ? origin + rawUrl : rawUrl;
  }
  const priceEl = card.querySelector('.a-price .a-offscreen');
  let price = priceEl ? norm(priceEl.textContent) : '';
  if (!price) {
    const whole = card.querySelector('.a-price-whole');
    if (whole) price = norm(whole.textContent);
  }
  if (!price) {
    const currencyRe = /(?:US\$|INR|GBP|EUR|CAD|AUD|JPY|CNY|\$|£|€|¥|₹)\s?[\d.,]+/;
    const candSpans = card.querySelectorAll('span.a-color-base, span.a-color-price, span.a-price');
    for (const sp of candSpans) {
      const m = (sp.textContent || '').match(currencyRe);
      if (m) { price = norm(m[0]); break; }
    }
  }
  let rating = '';
  const ratingAlt = card.querySelector('.a-icon-star-small .a-icon-alt, .a-icon-star .a-icon-alt');
  if (ratingAlt) rating = norm(ratingAlt.textContent);
  if (!rating) {
    const ariaEl = card.querySelector('[aria-label*="out of"]');
    if (ariaEl) rating = norm(ariaEl.getAttribute('aria-label') || '');
  }
  rating = rating.replace(/,\s*rating details\s*$/i, '').trim();
  let reviewCount = '';
  const rcAnchor = card.querySelector("a.a-link-normal[href*='#customerReviews'], a[href*='customerReviews']");
  if (rcAnchor) {
    const inner = rcAnchor.querySelector('span.a-size-base, span');
    reviewCount = norm(inner ? inner.textContent : rcAnchor.textContent);
  }
  if (!reviewCount) {
    const ariaRc = card.querySelector('[aria-label$="ratings"], [aria-label$="rating"]');
    if (ariaRc) reviewCount = norm(ariaRc.getAttribute('aria-label') || '');
  }
  reviewCount = reviewCount.replace(/^[()]+|[()]+$/g, '').trim();
  out.push({ title, product_url: url, asin, price, rating, review_count: reviewCount });
}
return out;
